use std::{env,process};
struct P{b:Vec<u8>,i:usize}
impl P{fn ws(&mut self){while self.i<self.b.len()&&matches!(self.b[self.i],b' '|b'\t'|b'\n'|b'\r'|12|11){self.i+=1}}fn eat(&mut self,c:u8)->bool{self.ws();if self.b.get(self.i)==Some(&c){self.i+=1;true}else{false}}fn ck(v:f64)->Result<f64,String>{if v.is_finite(){Ok(v)}else{Err("non-finite value".into())}}fn num(&mut self)->Result<f64,String>{self.ws();let st=self.i;while self.i<self.b.len()&&self.b[self.i].is_ascii_digit(){self.i+=1}if self.b.get(self.i)==Some(&b'.'){self.i+=1;while self.i<self.b.len()&&self.b[self.i].is_ascii_digit(){self.i+=1}}if self.i==st||(self.i==st+1&&self.b[st]==b'.'){return Err("expected number".into())}if matches!(self.b.get(self.i),Some(b'e')|Some(b'E')){self.i+=1;if matches!(self.b.get(self.i),Some(b'+')|Some(b'-')){self.i+=1}let es=self.i;while self.i<self.b.len()&&self.b[self.i].is_ascii_digit(){self.i+=1}if self.i==es{return Err("malformed exponent".into())}}let x=std::str::from_utf8(&self.b[st..self.i]).unwrap().parse::<f64>().map_err(|_|"invalid number".to_string())?;Self::ck(x)}fn prim(&mut self)->Result<f64,String>{if self.eat(b'('){let v=self.add()?;if !self.eat(b')'){return Err("expected ')'".into())}Ok(v)}else{self.num()}}fn power(&mut self)->Result<f64,String>{let mut v=self.prim()?;if self.eat(b'^'){v=v.powf(self.unary()?)}Self::ck(v)}fn unary(&mut self)->Result<f64,String>{if self.eat(b'+'){let v=self.unary()?;Self::ck(v)}else if self.eat(b'-'){let v=-self.unary()?;Self::ck(v)}else{self.power()}}fn mul(&mut self)->Result<f64,String>{let mut v=self.unary()?;loop{if self.eat(b'*'){v*=self.unary()?}else if self.eat(b'/'){let r=self.unary()?;if r==0.0{return Err("division by zero".into())}v/=r}else if self.eat(b'%'){let r=self.unary()?;if r==0.0{return Err("remainder by zero".into())}v%=r}else{return Ok(v)}v=Self::ck(v)?}}fn add(&mut self)->Result<f64,String>{let mut v=self.mul()?;loop{if self.eat(b'+'){v+=self.mul()?}else if self.eat(b'-'){v-=self.mul()?}else{return Ok(v)}v=Self::ck(v)?}}fn parse(&mut self)->Result<f64,String>{let v=self.add()?;self.ws();if self.i!=self.b.len(){Err("trailing token".into())}else{Ok(v)}}}
fn main(){let a:Vec<String>=env::args().collect();let r=if a.len()!=2{Err("expected one expression".into())}else{P{b:a[1].as_bytes().to_vec(),i:0}.parse()};match r{Ok(v)=>println!("{:.17}",v),Err(e)=>{eprintln!("error: {}",e);process::exit(1)}}}
